using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Train the ML model and capture evaluation metrics
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");

var trainer = new ModelTrainerService();
var metrics = trainer.TrainAndEvaluate(dataPath, modelPath);
builder.Services.AddSingleton(metrics);

// Thread-safe pooled prediction engine for ASP.NET Core
builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.Logger.LogInformation(
    "Model trained — MicroAccuracy: {Micro:P2}, MacroAccuracy: {Macro:P2}, LogLoss: {LogLoss:F4}",
    metrics.MicroAccuracy, metrics.MacroAccuracy, metrics.LogLoss);

app.MapControllers();
app.Run();

